if let method = urlRequest.method, destination.encodesParametersInURL(for: method) {
    guard let url = urlRequest.url else {
        throw AFError.parameterEncodingFailed(reason: .missingURL)
    }

    if var urlComponents = URLComponents(url: url, resolvingAgainstBaseURL: false), !parameters.isEmpty {
        let percentEncodedQuery = (urlComponents.percentEncodedQuery.map { $0 + "&" } ?? "") + query(parameters)
        urlComponents.percentEncodedQuery = percentEncodedQuery
        urlRequest.url = urlComponents.url
    }
} else {
    if urlRequest.headers["Content-Type"] == nil {
        urlRequest.headers.update(.contentType("application/x-www-form-urlencoded; charset=utf-8"))
    }

    urlRequest.httpBody = Data(query(parameters).utf8)
}

switch value {
case let dictionary as [String: Any]:
    for (nestedKey, value) in dictionary {
        components += queryComponents(fromKey: "\(key)[\(nestedKey)]", value: value)
    }
case let array as [Any]:
    for (index, value) in array.enumerated() {
        components += queryComponents(fromKey: arrayEncoding.encode(key: key, atIndex: index), value: value)
    }
case let number as NSNumber:
    if number.isBool {
        components.append((escape(key), escape(boolEncoding.encode(value: number.boolValue))))
    } else {
        components.append((escape(key), escape("\(number)")))
    }
case let bool as Bool:
    components.append((escape(key), escape(boolEncoding.encode(value: bool))))
default:
    components.append((escape(key), escape("\(value)")))
}

if let credentialStorage = delegate?.sessionConfiguration.urlCredentialStorage {
    let protectionSpace = URLProtectionSpace(host: host,
                                             port: url.port ?? 0,
                                             protocol: url.scheme,
                                             realm: host,
                                             authenticationMethod: NSURLAuthenticationMethodHTTPBasic)

    if let credentials = credentialStorage.credentials(for: protectionSpace)?.values {
        for credential in credentials {
            guard let user = credential.user, let password = credential.password else { continue }
            components.append("-u \(user):\(password)")
        }
    } else {
        if let credential, let user = credential.user, let password = credential.password {
            components.append("-u \(user):\(password)")
        }
    }
}

while true {
  let nextChunk = self[currentIndex...].prefix(columns)
  if let lastLineBreak = nextChunk.lastIndex(of: "\n") {
    result.append(
      contentsOf: self[currentIndex..<lastLineBreak].split(
        separator: "\n", omittingEmptySubsequences: false))
    currentIndex = index(after: lastLineBreak)
  } else if nextChunk.endIndex == self.endIndex {
    result.append(self[currentIndex...])
    break
  } else if let lastSpace = nextChunk.lastIndex(of: " ") {
    result.append(self[currentIndex..<lastSpace])
    currentIndex = index(after: lastSpace)
  } else if let nextSpace = self[currentIndex...].firstIndex(of: " ") {
    result.append(self[currentIndex..<nextSpace])
    currentIndex = index(after: nextSpace)
  } else {
    result.append(self[currentIndex...])
    break
  }
}

for index in indices {
  let nextIndex = self.index(after: index)
  let character = self[index]
  if character.isUppercase {
    if separateOnUppercase && !result.isEmpty {
      // Append the separator.
      result += "\(separator)"
    }
    // If the next character is uppercase and the next-next character is lowercase, like "L" in "URLSession", we should separate words.
    separateOnUppercase =
      nextIndex < endIndex && self[nextIndex].isUppercase
      && self.index(after: nextIndex) < endIndex
      && self[self.index(after: nextIndex)].isLowercase
  } else {
    // If the character is `separator`, we do not want to append another separator when we see the next uppercase character.
    separateOnUppercase = character != separator
  }
  // Append the lowercased character.
  result += character.lowercased()
}

for i in 1...m {
  swap(&previousRow, &currentRow)
  currentRow[0] = i

  var targetIdx = newTarget.startIndex
  for j in 1...n {
    // If characteres are equal for the levenshtein algorithm the
    // minimum will always be the substitution cost, so we can fast
    // path here in order to avoid min calls.
    if newSelf[sourceIdx] == newTarget[targetIdx] {
      currentRow[j] = previousRow[j - 1]
    } else {
      let deletion = previousRow[j]
      let insertion = currentRow[j - 1]
      let substitution = previousRow[j - 1]
      currentRow[j] =
        Swift.min(deletion, Swift.min(insertion, substitution)) + 1
    }
    // j += 1
    newTarget.formIndex(after: &targetIdx)
  }
  // i += 1
  newSelf.formIndex(after: &sourceIdx)
}

if lc && rc {
  return read { l in
    other.read { r in
      var result: Builder = .empty(level)
      guard l.collisionHash == r.collisionHash else { return result }

      var removing = false
      let ritems = r.reverseItems
      for lslot: _HashSlot in stride(from: .zero, to: l.itemsEndSlot, by: 1) {
        let lp = l.itemPtr(at: lslot)
        let include = ritems.contains { $0.key == lp.pointee.key }
        if include, removing {
          result.addNewCollision(level, lp.pointee, l.collisionHash)
        }
        else if !include, !removing {
          removing = true
          result.copyCollisions(from: l, upTo: lslot)
        }
      }
      guard removing else { return nil }
      assert(result.count < self.count)
      return result
    }
  }
}

if lc {
  // `self` is a collision node on a compressed path. The other tree might
  // have the same set of collisions, just expanded a bit deeper.
  return read { l in
    other.read { r in
      let bucket = l.collisionHash[level]
      if r.itemMap.contains(bucket) {
        let rslot = r.itemMap.slot(of: bucket)
        let ritem = r.itemPtr(at: rslot)
        let litems = l.reverseItems
        let i = litems.firstIndex { $0.key == ritem.pointee.key }
        guard let i = i else { return .empty(level) }
        return .item(level, litems[i], at: l.collisionHash[level])
      }
      if r.childMap.contains(bucket) {
        let rslot = r.childMap.slot(of: bucket)
        return _intersection(level.descend(), r[child: rslot])
          .map { .childBranch(level, $0, at: bucket) }
      }
      return .empty(level)
    }
  }
}

if self.isCollisionNode {
  if other.isCollisionNode {
    guard self.collisionHash == other.collisionHash else { return false }
    return read { l in
      other.read { r in
        let li = l.reverseItems
        let ri = r.reverseItems
        return l.reverseItems.indices.allSatisfy { i in
          ri.contains { $0.key == li[i].key }
        }
      }
    }
  }
  // `self` is on a compressed path. Try to descend down by one level.
  assert(!level.isAtBottom)
  let bucket = self.collisionHash[level]
  return other.read {
    guard $0.childMap.contains(bucket) else { return false }
    let slot = $0.childMap.slot(of: bucket)
    return self.isSubset(level.descend(), of: $0[child: slot])
  }
}

if lc && rc {
  return read { l in
    other.read { r in
      guard l.collisionHash == r.collisionHash else {
        return nil
      }
      var result: Builder = .empty(level)
      var removing = false

      let ritems = r.reverseItems
      for lslot: _HashSlot in stride(from: .zero, to: l.itemsEndSlot, by: 1) {
        let lp = l.itemPtr(at: lslot)
        let include = !ritems.contains { $0.key == lp.pointee.key }
        if include, removing {
          result.addNewCollision(level, lp.pointee, l.collisionHash)
        }
        else if !include, !removing {
          removing = true
          result.copyCollisions(from: l, upTo: lslot)
        }
      }
      guard removing else { return nil }
      assert(result.count < self.count)
      return result
    }
  }
}

if #available(macOS 12.3, iOS 15.4, watchOS 8.5, tvOS 15.4, *),
       let keyType = Key.self as? CodingKeyRepresentable.Type {
      // The keys are CodingKeyRepresentable, so we should be able to expect
      // a keyed container.
      let container = try decoder.container(keyedBy: _DictionaryCodingKey.self)
      for codingKey in container.allKeys {
        guard let key: Key = keyType.init(codingKey: codingKey) as? Key else {
          throw DecodingError.dataCorruptedError(
            forKey: codingKey,
            in: container,
            debugDescription: "Could not convert key to type \(Key.self)"
          )
        }
        let value: Value = try container.decode(Value.self, forKey: codingKey)
        self[key] = value
      }
      return
    }

if i > lastBreak {
  result._characters = 0
  result._prefix = result.utf8
  result._suffix = result.utf8
} else if i <= firstBreak {
  result._characters = self.counts._characters
  result.prefix = self.counts.prefix - i.utf8Offset
  result._suffix = self.counts._suffix
} else { // i > firstBreak, i <= lastBreak
  result._suffix = self.counts._suffix
  let prevBreak = characterIndex(roundingDown: i, in: firstBreak..<lastBreak)
  var state = _CharacterRecognizer(partialCharacter: utf8Span(from: prevBreak, to: i))
  if let (characters, first, _) = state.consume(self, i..<lastBreak) {
    assert(first >= i)
    result.characters = characters + 1
    result.prefix = utf8Distance(from: i, to: first)
  } else {
    result.characters = 1
    result.prefix = utf8Distance(from: i, to: lastBreak)
  }
}

switch utf8ScalarLength(x) {
case 2:
  let x = UInt32(x & 0b0001_1111)
  let cont = UInt32(_bytes[i.offset(by: 1).utf8Offset] & 0b0011_1111)
  let c = (x &<< 6) | cont
  return Unicode.Scalar(c).unsafelyUnwrapped
case 3:
  let x = UInt32(x & 0b0000_1111)
  let cont1 = UInt32(_bytes[i.offset(by: 1).utf8Offset] & 0b0011_1111)
  let cont2 = UInt32(_bytes[i.offset(by: 2).utf8Offset] & 0b0011_1111)
  let c = (x &<< 12) | (cont1 &<< 6) | cont2
  return Unicode.Scalar(c).unsafelyUnwrapped
case 4:
  let x = UInt32(x & 0b0000_0111)
  let cont1 = UInt32(_bytes[i.offset(by: 1).utf8Offset] & 0b0011_1111)
  let cont2 = UInt32(_bytes[i.offset(by: 2).utf8Offset] & 0b0011_1111)
  let cont3 = UInt32(_bytes[i.offset(by: 3).utf8Offset] & 0b0011_1111)
  let c = (x &<< 18) | (cont1 &<< 12) | (cont2 &<< 6) | cont3
  return Unicode.Scalar(c).unsafelyUnwrapped
default:
  fatalError()
}

if slot >= 0 {
  // elem[slot] <= key. Also check child[slot+1] for a greater
  // element still <= key.
  offset += slot
  for i in 0..<slot {
    offset += handle[childAt: i].read({ $0.subtreeCount })
  }
  offset += handle[childAt: slot].read({ $0.subtreeCount })
  // offset = position of elem[slot]

  let elemOffset = offset
  let savedDepth = childSlots.depth
  childSlots.append(UInt16(slot + 1))
  offset += 1  // step past elem[slot] to the start of child[slot+1]

  if let foundLater = search(in: handle[childAt: slot + 1]) {
    return foundLater
  }
  childSlots.depth = savedDepth
  targetSlot = slot
  offset = elemOffset
  return .passUnretained(node.storage)
} else {
  // key < all elements here: descend into the leftmost child.
  childSlots.append(UInt16(0))
  return search(in: handle[childAt: 0])
}

if let nextBufferSize = self.recvAllocator.nextBufferSize() {
    if let result = try self._buffer?._modifyIfUniquelyOwned(minimumCapacity: nextBufferSize, body) {
        // `result` can only be non-nil if `buffer` is non-nil.
        return (self._buffer!, result)
    } else {
        // Cycle through the buffers starting at the last used buffer.
        let resultAndIndex = try self._buffers._loopingFirstIndexWithResult(startingAt: self._lastUsedIndex) {
            buffer in
            try buffer._modifyIfUniquelyOwned(minimumCapacity: nextBufferSize, body)
        }

        if let (result, index) = resultAndIndex {
            self._lastUsedIndex = index
            return (self._buffers[index], result)
        }
    }
} else if self._buffer != nil, !self._mayGrow {
    // No hint about the buffer size (so pooling is not being used) and the allocator
    // indicated that the next buffer will not grow in size so reuse the existing stored
    // buffer.
    self._buffer!.clear()
    let result = try body(&self._buffer!)
    return (self._buffer!, result)
}

switch (arg1, arg1.flatMap(Int.init), arg2.flatMap(Int.init)) {
case (_, .some(let cid), .some(let port)):
    // we got two arguments (Int, Int), let's interpret that as vsock cid and port
    connectTarget = .vsock(
        VsockAddress(
            cid: VsockAddress.ContextID(cid),
            port: VsockAddress.Port(port)
        )
    )
case (.some(let h), .none, .some(let p)):
    // we got two arguments (String, Int), let's interpret that as host and port
    connectTarget = .ip(host: h, port: p)
case (.some(let portString), .none, .none):
    // we got one argument (String), let's interpret that as unix domain socket path
    connectTarget = .unixDomainSocket(path: portString)
case (_, .some(let p), _):
    // we got one argument (Int), let's interpret that as port on default host
    connectTarget = .ip(host: defaultHost, port: p)
default:
    connectTarget = .ip(host: defaultHost, port: defaultPort)
}

switch (arg1, arg1.flatMap(Int.init), arg2.flatMap(Int.init)) {
case (_, .some(let cid), .some(let port)):
    // we got two arguments (Int, Int), let's interpret that as vsock cid and port
    bindTarget = .vsock(
        VsockAddress(
            cid: VsockAddress.ContextID(cid),
            port: VsockAddress.Port(port)
        )
    )
case (.some(let h), _, .some(let p)):
    // we got two arguments (String, Int), let's interpret that as host and port
    bindTarget = .ip(host: h, port: p)
case (.some(let pathString), .none, .none):
    // we got one argument (String), let's interpret that unix domain socket path
    bindTarget = .unixDomainSocket(path: pathString)
case (_, .some(let p), .none):
    // we got one argument (Int), let's interpret that as port on default host
    bindTarget = .ip(host: defaultHost, port: p)
default:
    bindTarget = .ip(host: defaultHost, port: defaultPort)
}

switch hasBody {
case .no:
    headers.remove(name: "content-length")
    headers.remove(name: "transfer-encoding")
    return .neither
case .yes:
    if headers.contains(name: "content-length") {
        headers.remove(name: "transfer-encoding")
        return .contentLength
    }
    if version.major == 1 && version.minor >= 1 {
        headers.replaceOrAdd(name: "transfer-encoding", value: "chunked")
        return .chunked
    } else {
        return .neither
    }
case .unlikely:
    if headers.contains(name: "content-length") {
        headers.remove(name: "transfer-encoding")
        return .contentLength
    }
    if version.major == 1 && version.minor >= 1 {
        return headers["transfer-encoding"].first == "chunked" ? .chunked : .neither
    }
    return .neither
}

if controlMessage.type == ControlMessageParser.ipv4TosType {
    if let data = controlMessage.data {
        assert(data.count == 1)
        precondition(data.count >= 1)
        let readValue = CInt(data[0])
        self.ecnValue = .init(receivedValue: readValue)
    }
} else if controlMessage.type == Posix.IP_PKTINFO {
    #if !os(OpenBSD)
    if let data = controlMessage.data {
        let info = data.load(as: in_pktinfo.self)
        var addr = sockaddr_in()
        addr.sin_family = sa_family_t(NIOBSDSocket.AddressFamily.inet.rawValue)
        addr.sin_port = in_port_t(0)
        addr.sin_addr = info.ipi_addr
        self.packetInfo = NIOPacketInfo(
            destinationAddress: SocketAddress(addr, host: ""),
            interfaceIndex: Int(info.ipi_ifindex)
        )
    }
    #endif
}

for (input, expectedOutputs) in inputOutputPairs.shuffled() {
    try channel.writeInbound(input)
    for expectedOutput in expectedOutputs {
        guard let actualOutput = try channel.readInbound(as: Out.self) else {
            throw VerificationError<Out>(
                inputs: channel.inboundWrites,
                errorCode: .underProduction(expectedOutput)
            )
        }
        guard actualOutput == expectedOutput else {
            throw VerificationError<Out>(
                inputs: channel.inboundWrites,
                errorCode: .wrongProduction(
                    actual: actualOutput,
                    expected: expectedOutput
                )
            )
        }
    }
    let actualExtraOutput = try channel.readInbound(as: Out.self)
    guard actualExtraOutput == nil else {
        throw VerificationError<Out>(
            inputs: channel.inboundWrites,
            errorCode: .overProduction(actualExtraOutput!)
        )
    }
}

while buffer.readableBytes >= 4 {
    let extensionType: UInt16 = try buffer.readIntegerIfPossible()
    let extensionLength: UInt16 = try buffer.readIntegerIfPossible()

    guard buffer.readableBytes >= extensionLength else {
        throw InternalSNIErrors.invalidLengthInRecord
    }

    guard extensionType == sniExtensionType else {
        // Move forward by the length of this extension.
        try buffer.moveReaderIndexIfPossible(forwardBy: Int(extensionLength))
        continue
    }

    // We've found the server name extension. It's possible a malicious client could attempt a confused
    // deputy attack by giving us contradictory lengths, so we again want to trim the bytebuffer down
    // so that we never read past the advertised length of this extension.
    buffer = buffer.getSlice(at: buffer.readerIndex, length: Int(extensionLength))!
    return try parseServerNameExtension(buffer: &buffer)
}

while buffer.readableBytes > 0 {
    let nameType: UInt8 = try buffer.readIntegerIfPossible()

    // From the RFC:
    // "For backward compatibility, all future data structures associated with new NameTypes
    // MUST begin with a 16-bit length field."
    let nameLength: UInt16 = try buffer.readIntegerIfPossible()
    guard nameType == sniHostNameType else {
        try buffer.moveReaderIndexIfPossible(forwardBy: Int(nameLength))
        continue
    }

    let hostname = buffer.withUnsafeReadableBytes { ptr -> String? in
        let nameLength = Int(nameLength)
        guard nameLength <= ptr.count else {
            return nil
        }
        return UnsafeRawBufferPointer(rebasing: ptr.prefix(nameLength)).decodeStringValidatingASCII()
    }
    if let hostname = hostname {
        return hostname
    } else {
        throw InternalSNIErrors.invalidRecord
    }
}

switch self {
case .element(let element, let attribute, _):
  if attribute != .ignored,
    let parameterClause = element.parameterClause,
    parameterClause.parameters.count == 1,
    let parameter = parameterClause.parameters.first,
    parameter.type.is(IdentifierTypeSyntax.self) || parameter.type.is(MemberTypeSyntax.self)
  {
    if let type = parameter.type.as(IdentifierTypeSyntax.self),
      type.isEphemeral,
      let generics = type.genericArgumentClause?.arguments,
      generics.count == 1,
      let generic = generics.first?.argument.trimmedDescription
    {
      return "case \(element.name)(\(generic))"
    } else {
      return "case \(element.suffixed("Action").type.trimmedDescription)"
    }
  } else {
    return "case \(element.name)(Swift.Never)"
  }

case .ifConfig(let configs):
  return Self.renderedIfConfig(configs) { $0.actionCaseDecl } ?? ""
}

switch self {
case .element(let element, let attribute, let explicitActionType):
  if attribute == nil,
    let parameterClause = element.parameterClause,
    parameterClause.parameters.count == 1,
    let parameter = parameterClause.parameters.first,
    parameter.type.is(IdentifierTypeSyntax.self) || parameter.type.is(MemberTypeSyntax.self)
  {
    let name = element.name.text
    let type = parameter.type
    return "case \(name)(ComposableArchitecture.StoreOf<\(type.trimmed)>)"
  } else if let explicitActionType,
    let parameterClause = element.parameterClause,
    parameterClause.parameters.count == 1,
    let parameter = parameterClause.parameters.first
  {
    let name = element.name.text
    let stateType = parameter.type
    return
      "case \(name)(ComposableArchitecture.Store<\(stateType.trimmed), \(explicitActionType.trimmed)>)"
  } else {
    return "case \(element.trimmedDescription)"
  }
case .ifConfig(let configs):
  return Self.renderedIfConfig(configs) { $0.storeCase } ?? ""
}
